#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2.GameContent.Buffs;
using MVZ2.GameContent.Buffs.Entities;
using MVZ2.GameContent.Detections;
using MVZ2.GameContent.Effects;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Contraptions;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Auras;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaContraptionNames.transfenser)]
    public class Transfenser : DispenserFamily
    {
        public Transfenser(string nsp, string name) : base(nsp, name)
        {
            AddAura(new AimerAura());
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            InitShootTimer(entity);
        }
        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            if (entity.IsEvoked())
            {
                EvokedUpdate(entity);
            }
            else
            {
                if (IsShooterMode(entity))
                {
                    ShootTick(entity);
                }
                else if (IsTransforming(entity))
                {
                    UpdateTransforming(entity);
                }
            }
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            if (IsAimerMode(entity))
            {
                UpdateAimerAnimation(entity);
            }
            entity.SetAnimationBool("LaserActive", IsAimerMode(entity) && !entity.IsAIFrozen());
            entity.SetAnimationInt("TransformState", GetAnimationTransformState(entity));
            entity.SetAnimationFloat("TransformSpeed", entity.IsAIFrozen() ? 0 : 1);
        }
        protected override int GetTimerTime(Entity entity)
        {
            if (entity.Level.IsIZombie())
            {
                return ATTACK_INTERVAL_MAX;
            }
            return entity.RNG.Next(ATTACK_INTERVAL_MIN, ATTACK_INTERVAL_MAX + 1);
        }

        #region ┤ÑÀó
        public override bool CanTrigger(Entity entity)
        {
            if (Transfenser.IsTransforming(entity) || entity.IsEvoked())
            {
                return false;
            }
            return base.CanTrigger(entity);
        }
        public override void Trigger(Entity entity)
        {
            base.Trigger(entity);
            Transfenser.StartTransforming(entity);
            entity.PlaySound(VanillaSoundID.mechSetup);
        }
        #endregion

        #region ╝ñÀó
        public override bool CanEvoke(Entity entity)
        {
            if (Transfenser.IsTransforming(entity))
            {
                return false;
            }
            return base.CanEvoke(entity);
        }
        protected override void OnEvoke(Entity entity)
        {
            base.OnEvoke(entity);
            if (IsAimerMode(entity))
            {
                var offset = SHOOT_OFFSET;
                offset.x *= entity.GetFacingX();
                var sourcePosition = entity.Position + offset;

                var laserID = VanillaEffectID.megaGlowingLaser;
                entity.SpawnWithParams(laserID, sourcePosition);
            }
            else if (IsShooterMode(entity))
            {
                var evocationTimer = GetEvocationTimer(entity);
                evocationTimer?.Reset();
                entity.SetEvoked(true);
            }
        }
        private void EvokedUpdate(Entity entity)
        {
            var evocationTimer = GetEvocationTimer(entity);
            if (evocationTimer == null)
            {
                evocationTimer = TimerHelper.NewSecondTimer(EVOCATION_DURATION_SECONDS);
                SetEvocationTimer(entity, evocationTimer);
            }
            evocationTimer.Run();
            if (evocationTimer.PassedInterval(4))
            {
                var projectile = Shoot(entity);
                if (projectile != null)
                    projectile.Velocity *= 2;
            }
            if (evocationTimer.Expired)
            {
                entity.SetEvoked(false);
                var shootTimer = GetShootTimer(entity);
                shootTimer?.Reset();
            }
        }
        #endregion

        #region ▒õð╬
        private void UpdateTransforming(Entity entity)
        {
            var timer = GetTransformTimer(entity);
            if (timer == null)
            {
                timer = TimerHelper.NewSecondTimer(TRANSFORM_TIME_SECONDS);
                SetTransformTimer(entity, timer);
            }
            if (timer.RunToExpired())
            {
                EndTransforming(entity);
            }
        }
        public static void StartTransforming(Entity entity)
        {
            if (entity.State == STATE_SHOOTER)
            {
                entity.State = STATE_TO_AIMER;
            }
            else
            {
                entity.State = STATE_TO_SHOOTER;
            }
            var timer = GetTransformTimer(entity);
            timer?.Reset();
        }
        private void EndTransforming(Entity entity)
        {
            if (entity.State == STATE_TO_AIMER)
            {
                entity.State = STATE_AIMER;
                var aura = entity.GetAuraEffect<AimerAura>();
                if (aura != null)
                {
                    aura.UpdateAura();
                }
                UpdateAimerAnimation(entity);
            }
            else
            {
                entity.State = STATE_SHOOTER;
            }
        }
        #endregion

        #region ─ú╩¢┼ðÂ¤
        public static bool IsShooterMode(Entity entity)
        {
            return entity.State == STATE_SHOOTER;
        }
        public static bool IsAimerMode(Entity entity)
        {
            return entity.State == STATE_AIMER;
        }
        public static bool IsTransforming(Entity entity)
        {
            return entity.State == STATE_TO_AIMER || entity.State == STATE_TO_SHOOTER;
        }
        #endregion

        #region Â»╗¡ã¸
        private void UpdateAimerAnimation(Entity entity)
        {
            var aura = entity.GetAuraEffect<AimerAura>();
            if (aura != null)
            {
                float range = MAX_LASER_RANGE;
                var target = aura.GetFirstTarget();
                if (target != null && target.GetEntity() is Entity targetEntity)
                {
                    var direction = targetEntity.GetCenter() - entity.GetCenter();
                    range = Vector3.Dot(direction, entity.GetFacingDirection());
                }
                entity.SetAnimationFloat("LaserLength", range);
            }
        }
        public static int GetAnimationTransformState(Entity entity)
        {
            switch (entity.State)
            {
                case STATE_TO_AIMER:
                    return TRANSFORM_STATE_TO_AIMER;
                case STATE_AIMER:
                    return TRANSFORM_STATE_AIMER;
                case STATE_TO_SHOOTER:
                    return TRANSFORM_STATE_TO_SHOOTER;
            }
            return TRANSFORM_STATE_SHOOTER;
        }
        #endregion

        #region ╩¶ðÈ
        public static FrameTimer? GetTransformTimer(Entity entity)
        {
            return entity.GetProperty<FrameTimer>(PROP_TRANSFORM_TIMER);
        }
        public static void SetTransformTimer(Entity entity, FrameTimer? value)
        {
            entity.SetProperty(PROP_TRANSFORM_TIMER, value);
        }
        public static FrameTimer? GetEvocationTimer(Entity entity) => entity.GetProperty<FrameTimer>(PROP_EVOCATION_TIMER);
        public static void SetEvocationTimer(Entity entity, FrameTimer timer) => entity.SetProperty(PROP_EVOCATION_TIMER, timer);
        #endregion

        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_EVOCATION_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("evocation_timer");
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_TRANSFORM_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("transform_timer");

        public static readonly Vector3 SHOOT_OFFSET = new Vector3(12, 40, 0);
        public const int ATTACK_INTERVAL_MIN = 80;
        public const int ATTACK_INTERVAL_MAX = 90;
        public const int MAX_LASER_RANGE = 2000;
        public const float TRANSFORM_TIME_SECONDS = 1f;
        public const float EVOCATION_DURATION_SECONDS = 4f;

        public const int STATE_SHOOTER = VanillaContraptionStates.IDLE;
        public const int STATE_TO_AIMER = VanillaContraptionStates.TRANSFENSER_TO_AIMER;
        public const int STATE_AIMER = VanillaContraptionStates.TRANSFENSER_AIMER;
        public const int STATE_TO_SHOOTER = VanillaContraptionStates.TRANSFENSER_TO_SHOOTER;

        public const int TRANSFORM_STATE_SHOOTER = 0;
        public const int TRANSFORM_STATE_TO_AIMER = 1;
        public const int TRANSFORM_STATE_AIMER = 2;
        public const int TRANSFORM_STATE_TO_SHOOTER = 3;


        public class AimerAura : AuraEffectDefinition
        {
            public AimerAura() : base(VanillaBuffID.Entity.transfenserGlowing, 2)
            {
            }

            public override void GetAuraTargets(AuraEffect auraEffect, List<IBuffTarget> results)
            {
                var entity = auraEffect.Source.GetEntity();
                if (entity == null)
                    return;
                if (entity.IsAIFrozen() || !Transfenser.IsAimerMode(entity))
                    return;
                var facingX = entity.GetFacingX();
                var target = laserDetector.DetectEntityWithTheLeast(entity, (target) => (target.Position - entity.Position).x * facingX);
                if (target == null)
                    return;
                results.Add(target);
            }
            public override void UpdateTargetBuff(AuraEffect effect, IBuffTarget target, Buff buff)
            {
                base.UpdateTargetBuff(effect, target, buff);
                TransfenserGlowingBuff.MaxTime(buff, 3);
            }
            public static Detector laserDetector = new TransfenserLaserDetector(SHOOT_OFFSET, MAX_LASER_RANGE)
            {
                canDetectInvisible = true
            };
        }
    }
}
